//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageglobalacceleratorimport(	"fmt"	"strings"	"github.com/aws/aws-sdk-go/aws/arn")const(	ARNSeparator="/"	ARNService="globalaccelerator")//EndpointGroupARNToListenerARNconvertsanendpointgroupARNtoalistenerARN.//Seehttps://docs.aws.amazon.com/service-authorization/latest/reference/list_awsglobalaccelerator.html#awsglobalaccelerator-resources-for-iam-policies.funcEndpointGroupARNToListenerARN(inputARNstring)(string,error){	parsedARN,err:=arn.Parse(inputARN)	iferr!=nil{		return"",fmt.Errorf("parsingARN(%s):%w",inputARN,err)	}	ifactual,expected:=parsedARN.Service,ARNService;actual!=expected{		return"",fmt.Errorf("expectedservice%sinARN(%s),got:%s",expected,inputARN,actual)	}	resourceParts:=strings.Split(parsedARN.Resource,ARNSeparator)	ifactual,expected:=len(resourceParts),6;actual<expected{		return"",fmt.Errorf("expectedatleast%dresourcepartsinARN(%s),got:%d",expected,inputARN,actual)	}	outputARN:=arn.ARN{		Partition:parsedARN.Partition,		Service:parsedARN.Service,		Region:parsedARN.Region,		AccountID:parsedARN.AccountID,		Resource:strings.Join(resourceParts[0:4],ARNSeparator),	}.String()	returnoutputARN,nil}//ListenerOrEndpointGroupARNToAcceleratorARNconvertsalistenerorendpointgroupARNtoanacceleratorARN.//Seehttps://docs.aws.amazon.com/service-authorization/latest/reference/list_awsglobalaccelerator.html#awsglobalaccelerator-resources-for-iam-policies.funcListenerOrEndpointGroupARNToAcceleratorARN(inputARNstring)(string,error){	parsedARN,err:=arn.Parse(inputARN)	iferr!=nil{		return"",fmt.Errorf("parsingARN(%s):%w",inputARN,err)	}	ifactual,expected:=parsedARN.Service,ARNService;actual!=expected{		return"",fmt.Errorf("expectedservice%sinARN(%s),got:%s",expected,inputARN,actual)	}	resourceParts:=strings.Split(parsedARN.Resource,ARNSeparator)	ifactual,expected:=len(resourceParts),4;actual<expected{		return"",fmt.Errorf("expectedatleast%dresourcepartsinARN(%s),got:%d",expected,inputARN,actual)	}	outputARN:=arn.ARN{		Partition:parsedARN.Partition,		Service:parsedARN.Service,		Region:parsedARN.Region,		AccountID:parsedARN.AccountID,		Resource:strings.Join(resourceParts[0:2],ARNSeparator),	}.String()	returnoutputARN,nil}